## Deep Dive: API Test Automation Framework Design

### Framework Architecture

A well-structured API test automation framework follows a layered architecture:

```
tests/
  conftest.py              # Shared fixtures
  api/
    test_users.py          # Test classes/functions
    test_orders.py
  integration/
    test_user_orders.py

framework/
  client.py               # HTTP client wrapper
  auth.py                 # Authentication module
  config.py               # Configuration management
  validators.py           # Response validation helpers
  models/
    user.py               # Response models (Pydantic/dataclass)
    order.py
  services/
    user_service.py        # API endpoint wrappers
    order_service.py
  data/
    factories.py           # Test data factories
    fixtures/              # Static test data files
```

### Service Object Pattern

Encapsulate API endpoints into service classes. This is the API equivalent of the Page Object Model:

```python
class UserService:
    def __init__(self, client: APIClient):
        self.client = client

    def create_user(self, name, email, role="viewer"):
        response = self.client.post("/api/users", json={
            "name": name, "email": email, "role": role
        })
        assert response.status_code == 201, f"Failed to create user: {response.text}"
        return response.json()

    def get_user(self, user_id):
        return self.client.get(f"/api/users/{user_id}")

    def list_users(self, page=1, per_page=20, filters=None):
        params = {"page": page, "per_page": per_page}
        if filters:
            params.update(filters)
        return self.client.get("/api/users", params=params)

    def update_user(self, user_id, **fields):
        return self.client.patch(f"/api/users/{user_id}", json=fields)

    def delete_user(self, user_id):
        return self.client.delete(f"/api/users/{user_id}")


class OrderService:
    def __init__(self, client: APIClient):
        self.client = client

    def create_order(self, customer_id, items):
        return self.client.post("/api/orders", json={
            "customer_id": customer_id,
            "items": items
        })

    def get_order(self, order_id):
        return self.client.get(f"/api/orders/{order_id}")

    def cancel_order(self, order_id, reason):
        return self.client.post(f"/api/orders/{order_id}/cancel", json={"reason": reason})
```

### Builder Pattern for Request Payloads

```python
class OrderBuilder:
    def __init__(self):
        self._data = {"items": [], "shipping_method": "standard"}

    def for_customer(self, customer_id):
        self._data["customer_id"] = customer_id
        return self

    def add_item(self, product_id, quantity=1):
        self._data["items"].append({"product_id": product_id, "quantity": quantity})
        return self

    def with_shipping(self, method):
        self._data["shipping_method"] = method
        return self

    def with_coupon(self, code):
        self._data["coupon_code"] = code
        return self

    def build(self):
        assert "customer_id" in self._data, "Customer ID is required"
        assert len(self._data["items"]) > 0, "At least one item is required"
        return self._data

# Usage
order_payload = (OrderBuilder()
    .for_customer(123)
    .add_item(product_id=1, quantity=2)
    .add_item(product_id=5, quantity=1)
    .with_shipping("express")
    .with_coupon("SAVE10")
    .build())
```

### Retry and Resilience

```python
import time
from functools import wraps

def retry(max_attempts=3, delay=1, backoff=2, exceptions=(Exception,)):
    def decorator(func):
        @wraps(func)
        def wrapper(*args, **kwargs):
            current_delay = delay
            for attempt in range(1, max_attempts + 1):
                try:
                    return func(*args, **kwargs)
                except exceptions as e:
                    if attempt == max_attempts:
                        raise
                    time.sleep(current_delay)
                    current_delay *= backoff
        return wrapper
    return decorator

class ResilientAPIClient(APIClient):
    @retry(max_attempts=3, delay=0.5, exceptions=(requests.ConnectionError, requests.Timeout))
    def _request(self, method, endpoint, **kwargs):
        return super()._request(method, endpoint, **kwargs)
```

### Request/Response Logging

```python
import json
import logging

class LoggingAPIClient(APIClient):
    def _request(self, method, endpoint, **kwargs):
        response = super()._request(method, endpoint, **kwargs)

        # Log full request/response for debugging
        self.logger.debug(f"Request: {method} {endpoint}")
        if "json" in kwargs:
            self.logger.debug(f"Request Body: {json.dumps(kwargs['json'], indent=2)}")
        self.logger.debug(f"Response Status: {response.status_code}")
        try:
            self.logger.debug(f"Response Body: {json.dumps(response.json(), indent=2)}")
        except ValueError:
            self.logger.debug(f"Response Body: {response.text[:500]}")

        return response
```

### Fixtures and Test Setup with pytest

```python
# conftest.py
import pytest

@pytest.fixture(scope="session")
def api_client():
    config = Config.from_env(os.getenv("TEST_ENV", "dev"))
    client = APIClient(config.base_url, timeout=config.timeout)
    return client

@pytest.fixture(scope="session")
def auth_client(api_client):
    api_client.authenticate(os.environ["TEST_USER"], os.environ["TEST_PASS"])
    return api_client

@pytest.fixture
def user_service(auth_client):
    return UserService(auth_client)

@pytest.fixture
def test_user(user_service):
    """Create a test user, yield it, then delete."""
    user = user_service.create_user(name="Test User", email=f"test-{uuid4()}@example.com")
    yield user
    user_service.delete_user(user["id"])
```
